// src/components/Navbar.js
import React, { useState } from "react";
import { Link } from "react-router-dom";
import { Search, X, Menu } from "lucide-react";
import logo from "../assets/logo.png"; // Ensure logo exists in assets

function Navbar({ onSearchClick }) {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  return (
    <nav className="w-full bg-black text-white fixed top-0 z-50 shadow-md">
      <div className="max-w-7xl mx-auto px-6 md:px-10 flex justify-between items-center h-16">
        {/* Logo & Brand */}
        <div className="flex items-center space-x-2">
          <img src={logo} alt="Godemar Logo" className="w-10 h-10" />
          <span className="font-bold text-xl">Godemar’s Empire</span>
        </div>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center space-x-6">
          <Link to="/" className="hover:text-yellow-500">Home</Link>
          <Link to="/about" className="hover:text-yellow-500">About</Link>
          <Link to="/domains" className="hover:text-yellow-500">Domains</Link>
          <Link to="/vision" className="hover:text-yellow-500">Vision</Link>
          <Link to="/purpose" className="hover:text-yellow-500">Purpose</Link>
          <Link to="/team" className="hover:text-yellow-500">Team</Link>
          <Link to="/careers" className="hover:text-yellow-500">Careers</Link>
          <Link to="/contact" className="hover:text-yellow-500">Contact</Link>
          <button 
            onClick={onSearchClick}
            className="ml-2 p-2 hover:text-yellow-500"
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
        </div>

        {/* Mobile Hamburger */}
        <div className="md:hidden flex items-center">
          <button 
            onClick={onSearchClick} 
            className="mr-2 p-2" 
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
          <button 
            onClick={() => setIsMenuOpen(!isMenuOpen)} 
            aria-label="Toggle menu"
          >
            {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-black text-white px-6 py-4 space-y-4">
          <Link to="/" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">Home</Link>
          <Link to="/about" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">About</Link>
          <Link to="/domains" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">Domains</Link>
          <Link to="/vision" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">Vision</Link>
          <Link to="/purpose" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">Purpose</Link>
          <Link to="/team" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">Team</Link>
          <Link to="/careers" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">Careers</Link>
          <Link to="/contact" onClick={() => setIsMenuOpen(false)} className="block hover:text-yellow-500">Contact</Link>
        </div>
      )}
    </nav>
  );
}

export default Navbar;
